#include<bits/stdc++.h>
using namespace std;
int c[3010][3010];
const int mod=2333;
long long f(long long n,long long k)
{
    if(n<mod)
    {
        return c[n][min(n,k)];
    }
    if(k==0)
    {
        return 1;
    }
    int x=k%mod,y=n%mod;
    long long ans=c[y][min(x,y)]*f(n/mod,k/mod)%mod;
    if(k-x)
    {
        ans+=(c[y][y]-c[y][min(x,y)])*f(n/mod,(k-x-1)/mod)%mod;
    }
    return ans%mod;
}
int main()
{
    int t;
    scanf("%d",&t);
    for(int i=0;i<=3000;i++)
    {
        c[i][0]=1;
        for(int j=1;j<=i;j++)
        {
            c[i][j]=(c[i-1][j]+c[i-1][j-1])%mod;
        }
    }
    for(int i=0;i<=3000;i++)
    {
        for(int j=1;j<=i;j++)
        {
            c[i][j]=(c[i][j]+c[i][j-1])%mod;
        }
    }
    while(t--)
    {
        long long n,k;
        scanf("%lld%lld",&n,&k);
        printf("%lld\n",(f(n,k)%mod+mod)%mod);
    }
    return 0;
}
